122	  const grossPayout = sumBy(incident.damages, (d) => payoutForDamage(d, policy.items));
123	  const payout = Math.min(grossPayout, policy.remainingCap);
124	  policy.remainingCap -= payout;
125	  return { payout, remainingCap: policy.remainingCap };
126	};
127	
128	const quoteFor = ({ items }: QuoteStep, ctx: QuoteContext): QuoteResult => ({
