141	const handleStep = (step: Step, state: ScenarioState): StepResult =>
142	  step.op === "quote"
143	    ? handleQuote(step, state)
144	    : processClaim(state.policies[step.policy], step.incident);
145	
146	export const processScenario = (input: Scenario): { results: StepResult[] } => {
147	  const state: ScenarioState = { customer: input.customer, policies: [], quoteCount: 0 };
148	  const results = input.steps.map((step) => handleStep(step, state));
149	  return { results };
150	};
